import java.util.function.*;
public class FunctionChain {
    public static void main(String[] args) {
        Function<Integer,Integer> times3 = x -> x * 3;
        Function<Integer,Integer> plus10 = x -> x + 10;
        Function<Integer,Integer> composed = times3.andThen(plus10);
        Function<Integer,Integer> composed2 = times3.compose(plus10);
        System.out.println(composed.apply(5));
        System.out.println(composed2.apply(5));
    }
}
